'use client';
import { useState } from 'react';

function Counter({ label }: { label: string }) {
  const [count, setCount] = useState(0); // state: local to this component
  return (
    <button onClick={() => setCount(count + 1)}>
      {label}: {count}
    </button>
  );
}

// Parent passes label as a prop
<Counter label="Clicks" />

alternatives.code:
function Parent() {
  const [count, setCount] = useState(0);
  return (
    <>
      <Display count={count} />
      <Increment onClick={() => setCount(count + 1)} />
    </>
  );
}

